import React from 'react';

interface UserProfileProps {
  user: {
    name: string;
    bio: string;
    website: string;
  };
}

export function UserProfile({ user }: UserProfileProps) {
  return (
    <div className="user-profile">
      <h2>{user.name}</h2>
      <div
        className="bio"
        dangerouslySetInnerHTML={{ __html: user.bio }}
      />
      <a href={user.website}>Visit website</a>
    </div>
  );
}
